// Prepare data for InfluxDB - Handle specific required fields only
try {
    const data = msg.payload;

    // Validate input data
    if (!data || typeof data !== 'object') {
        node.error("Invalid payload - expected object");
        return null;
    }

    const timestamp = new Date().toISOString();

    // Function to ensure value is a valid number
    function ensureNumber(value) {
        if (value === null || value === undefined || value === "") return null;
        if (typeof value === 'number') {
            return isNaN(value) || !isFinite(value) ? null : Number(value.toFixed(3));
        }
        if (typeof value === 'string') {
            const cleaned = value.replace(/[^0-9.-]/g, '').trim();
            if (cleaned === '' || cleaned === '-' || cleaned === '.') return null;
            const num = parseFloat(cleaned);
            return isNaN(num) || !isFinite(num) ? null : Number(num.toFixed(3));
        }
        return null;
    }

    // Create fields object for specific required values only
    const fields = {};

    // Required fields mapping based on your specification
    const requiredFields = {
        // Voltage readings
        'voltage_v1n': data.voltage_v1n,
        'voltage_v2n': data.voltage_v2n, 
        'voltage_v3n': data.voltage_v3n,
        'average_voltage_ln': data.average_voltage_ln,

        // Current readings
        'current_i1': data.current_i1,
        'current_i2': data.current_i2,
        'current_i3': data.current_i3,
        'average_current': data.average_current,

        // Power readings (kW)
        'kw1': data.kw1,
        'kw2': data.kw2,
        'kw3': data.kw3,
        'total_kw': data.total_kw,

        // Apparent power (kVA)
        'kva1': data.kva1,
        'kva2': data.kva2,
        'kva3': data.kva3,
        'total_kva': data.total_kva,

        // Power factor
        'pf1': data.pf1 || data.power_factor1,
        'pf2': data.pf2 || data.power_factor2,
        'pf3': data.pf3 || data.power_factor3,
        'average_pf': data.average_pf || data.average_power_factor,

        // Frequency
        'frequency': data.frequency,

        // Energy readings
        'total_net_kwh': data.total_net_kwh,
        'total_net_kvah': data.total_net_kvah,

        // Maximum demand readings
        'max_i1_demand': data.max_i1_demand,
        'max_i2_demand': data.max_i2_demand,
        'max_i3_demand': data.max_i3_demand,
        'max_avg_i_demand': data.max_avg_i_demand
    };

    // Process only the required fields
    for (const [fieldName, value] of Object.entries(requiredFields)) {
        if (value !== undefined && value !== null) {
            const processedValue = ensureNumber(value);
            if (processedValue !== null) {
                fields[fieldName] = processedValue;
            }
        }
    }

    // Check if we have at least one valid field
    if (Object.keys(fields).length === 0) {
        node.warn("No valid required fields found. Available data fields: " + 
                  Object.keys(data).filter(key => !['raw_registers', 'unit', 'timestamp'].includes(key)).join(', '));
        return null;
    }

    // Create InfluxDB format with only required fields
    msg.payload = {
        ...fields,
        device: "SLT 1st floor",
        location: "Canteen"
    };

    node.log(`Sending ${Object.keys(fields).length} required parameters to InfluxDB: ${Object.keys(fields).join(', ')}`);

    return msg;

} catch (error) {
    node.error("Error preparing InfluxDB data: " + error.message);
    return null;
}

// Convert 2 registers to float32 for Voltage V3N
// Assuming big-endian byte order (most common)

if (msg.payload && msg.payload.length >= 2) {
    // Get the two 16-bit register values
    const reg1 = msg.payload[0];  // High register
    const reg2 = msg.payload[1];  // Low register

    // Create a buffer for the float conversion
    const buffer = Buffer.alloc(4);

    // Write as big-endian 16-bit values
    buffer.writeUInt16BE(reg1, 0);
    buffer.writeUInt16BE(reg2, 2);

    // Read as big-endian float32
    const voltageV3N = buffer.readFloatBE(0);

    msg.payload = {
        raw_registers: [reg1, reg2],
        voltage_v3n: voltageV3N,
        unit: "V",
        timestamp: new Date().toISOString()
    };

    return msg;
} else {
    node.error("Invalid payload received");
    return null;
}

