    unitid:   3,
    fc:       4,
    address:  1,
    quantity: 62
};
msg.topic = 'block_a';
return msg;

// Sequential parser for SLT 1st Floor Canteen
const topic = msg.topic;
const regs = msg.payload;

function readFloat(regs, startIndex) {
    if (!regs || regs.length < startIndex + 2) return null;
    const reg1 = regs[startIndex];
    const reg2 = regs[startIndex + 1];
    const buffer = Buffer.alloc(4);
    buffer.writeUInt16BE(reg1, 0);
    buffer.writeUInt16BE(reg2, 2);
    return buffer.readFloatBE(0);
}

// Retrieve accumulator
let blocks = flow.get('SLT_1st_Floor_blocks') || {};

if (!Array.isArray(regs)) {
    node.warn('SLT 1st Floor bad response on ' + topic + ': ' + JSON.stringify(regs));
} else {
    if (topic === 'block_a') {
        if (regs.length >= 62) {
            blocks.voltage_v1n = readFloat(regs, 0);
            blocks.voltage_v2n = readFloat(regs, 2);
            blocks.voltage_v3n = readFloat(regs, 4);
            blocks.average_voltage_ln = readFloat(regs, 6);

            blocks.current_i1 = readFloat(regs, 16);
            blocks.current_i2 = readFloat(regs, 18);
            blocks.current_i3 = readFloat(regs, 20);

            if (blocks.current_i1 !== null && blocks.current_i2 !== null && blocks.current_i3 !== null) {
                blocks.average_current = (blocks.current_i1 + blocks.current_i2 + blocks.current_i3) / 3;
            } else {
                blocks.average_current = null;
            }

            blocks.kw1 = readFloat(regs, 24);
            blocks.kw2 = readFloat(regs, 26);
            blocks.kw3 = readFloat(regs, 28);

            blocks.kva1 = readFloat(regs, 30);
            blocks.kva2 = readFloat(regs, 32);
            blocks.kva3 = readFloat(regs, 34);

            blocks.total_kw = readFloat(regs, 42);
            blocks.total_kva = readFloat(regs, 44);

            blocks.pf1 = blocks.power_factor1 = readFloat(regs, 48);
            blocks.pf2 = blocks.power_factor2 = readFloat(regs, 50);
            blocks.pf3 = blocks.power_factor3 = readFloat(regs, 52);
            blocks.average_pf = blocks.average_power_factor = readFloat(regs, 54);

            blocks.frequency = readFloat(regs, 56);

            blocks.total_net_kwh = readFloat(regs, 58);
            blocks.total_net_kvah = readFloat(regs, 60);
        } else {
            node.warn('SLT 1st Floor block_a short: ' + regs.length);
        }
    } else if (topic === 'block_b') {
        if (regs.length >= 8) {
            blocks.max_i1_demand = readFloat(regs, 0);
            blocks.max_i2_demand = readFloat(regs, 2);
            blocks.max_i3_demand = readFloat(regs, 4);
            blocks.max_avg_i_demand = readFloat(regs, 6);
        } else {
            node.warn('SLT 1st Floor block_b short: ' + regs.length);
        }
    }
}

// Save updated accumulator
flow.set('SLT_1st_Floor_blocks', blocks);

// Decide next action - send next request or finish
const sequence = {
    'block_a': { address: 693, quantity: 8, next: 'block_b' },
    'block_b': null
};

const next = sequence[topic];

if (next === null) {
    // Done - send combined payload
    msg.topic = 'done';
    msg.payload = blocks;
    flow.set('SLT_1st_Floor_blocks', {});
    return [null, msg];
} else if (next) {
    var nextMsg = {
        payload: {
            value:    0,
            unitid:   3,
            fc:       4,
            address:  next.address,
            quantity: next.quantity
        },
        topic: next.next
    };
    setTimeout(function() {
        node.send([nextMsg, null]);
    }, 500);
    return null;
} else {
    node.warn('Unknown topic: ' + topic);
    return [null, null];
}
